func solve(nums []int64, queries [][]int64) []int64 {
    var ans []int64
    n := len(nums)
    for _, query := range queries {
        li := query[0]
        ri := query[1]
        threshold := query[2]
        freq := make(map[int64]int64)
        for i := li; i <= ri; i++ {
            num := nums[i]
            freq[num]++
        }
        var result int64
        found := false
        for num, count := range freq {
            if count >= threshold {
                if !found {
                    result = num
                    found = true
                } else {
                    if count > freq[result] || (count == freq[result] && num < result) {
                        result = num
                    }
                }
            }
        }
        if found {
            ans = append(ans, result)
        } else {
            ans = append(ans, -1)
        }
    }
    return ans
}
